import{_ as i,o as a,c as e,ae as t}from"./chunks/framework.BD9pLfSD.js";const p=JSON.parse('{"title":"主试手册","description":"","frontmatter":{},"headers":[],"relativePath":"2-experimenter-manual/index.md","filePath":"2-experimenter-manual/index.md"}'),r={name:"2-experimenter-manual/index.md"};function o(n,l,h,s,u,d){return a(),e("div",null,[...l[0]||(l[0]=[t('<h1 id="主试手册" tabindex="-1">主试手册 <a class="header-anchor" href="#主试手册" aria-label="Permalink to &quot;主试手册&quot;">​</a></h1><p>欢迎使用CogniAND心理学实验平台！本手册将帮助您了解如何作为主试（研究者）使用平台的各项功能。</p><h2 id="什么是主试" tabindex="-1">什么是主试？ <a class="header-anchor" href="#什么是主试" aria-label="Permalink to &quot;什么是主试？&quot;">​</a></h2><p>主试是实验的设计者和管理者，负责创建实验、招募被试并管理实验数据。在CogniAND平台上，主试可以：</p><ul><li>✅ 查看和管理自己创建的实验</li><li>✅ 使用邀请系统招募被试</li><li>✅ 管理个人资料和角色</li><li>✅ 查看实验数据</li><li>✅ 创建和编辑实验</li></ul><h2 id="权限说明" tabindex="-1">权限说明 <a class="header-anchor" href="#权限说明" aria-label="Permalink to &quot;权限说明&quot;">​</a></h2><h3 id="主试可以做什么" tabindex="-1">主试可以做什么 <a class="header-anchor" href="#主试可以做什么" aria-label="Permalink to &quot;主试可以做什么&quot;">​</a></h3><ul><li>✅ 查看自己创建的实验</li><li>✅ 生成和管理邀请链接</li><li>✅ 发送邀请邮件</li><li>✅ 管理个人资料</li><li>✅ 切换角色</li><li>✅ 查看实验数据</li><li>✅ 创建新实验</li><li>✅ 编辑已发布的实验</li></ul><h3 id="主试不能做什么" tabindex="-1">主试不能做什么 <a class="header-anchor" href="#主试不能做什么" aria-label="Permalink to &quot;主试不能做什么&quot;">​</a></h3><ul><li>❌ 查看其他主试的实验数据</li><li>❌ 修改其他主试的实验</li><li>❌ 查看被试的个人隐私信息</li><li>❌ 删除被试提交的数据</li><li>❌ 访问管理员功能</li></ul><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><h3 id="实验伦理" tabindex="-1">实验伦理 <a class="header-anchor" href="#实验伦理" aria-label="Permalink to &quot;实验伦理&quot;">​</a></h3><p>作为主试，您需要遵守心理学研究伦理规范：</p><ol><li><p><strong>尊重原则</strong></p><ul><li>尊重被试的自主决定权</li><li>保护被试的隐私和尊严</li><li>不得歧视或侮辱被试</li></ul></li><li><p><strong>有益原则</strong></p><ul><li>实验应有科学价值和社会意义</li><li>最大化实验收益，最小化风险</li><li>及时向被试反馈实验结果（如适用）</li></ul></li><li><p><strong>公正原则</strong></p><ul><li>公平选择被试，不得歧视</li><li>合理分配实验收益和风险</li><li>保护弱势群体的权益</li></ul></li><li><p><strong>诚信原则</strong></p><ul><li>如实描述实验内容和风险</li><li>不得伪造或篡改数据</li><li>尊重学术规范和知识产权</li></ul></li></ol><p>详细说明：<a href="/5-data-privacy/4-ethics.html">数据与隐私 - 伦理合规</a></p><h3 id="数据保护" tabindex="-1">数据保护 <a class="header-anchor" href="#数据保护" aria-label="Permalink to &quot;数据保护&quot;">​</a></h3><ul><li>保护被试隐私，不得泄露个人信息</li><li>数据仅用于知情同意书中说明的用途</li><li>发表研究时应对数据进行匿名化处理</li><li>研究结束后按规定销毁或归档数据</li></ul><p>详细说明：<a href="/5-data-privacy/">数据与隐私</a></p><h2 id="需要帮助" tabindex="-1">需要帮助？ <a class="header-anchor" href="#需要帮助" aria-label="Permalink to &quot;需要帮助？&quot;">​</a></h2><ul><li>查看<a href="/1-FAQ/">常见问题 FAQ</a></li><li>查看<a href="/6-troubleshooting/">故障排除</a></li><li>联系<a href="/7-technical-support/1-contact.html">技术支持</a></li></ul><hr><p><strong>准备好开始了吗？</strong> 查看<a href="./1-getting-started.html">快速开始</a>开始您的第一个实验！</p>',22)])])}const m=i(r,[["render",o]]);export{p as __pageData,m as default};
